"use client";
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { CloudRain, Sun, Smile, Frown, Sparkles, Send, Coffee, ChevronRight, Activity, Play } from 'lucide-react';

const mockContext = {
  weather: 'hot / sunny', 
  userMood: 'tired', 
  pastOrders: ['Iced Caramel Macchiato', 'Blueberry Muffin']
};

const TypewriterMessage = ({ text, onComplete, onUpdate, fastForward }) => {
  const [displayed, setDisplayed] = useState('');
  const isFinished = useRef(false);
  
  useEffect(() => {
    if (isFinished.current) return;

    if (fastForward) {
       setDisplayed(text);
       isFinished.current = true;
       if (onComplete) onComplete();
       if (onUpdate) onUpdate();
       return;
    }

    let index = 0;
    let currentText = ''; 
    setDisplayed(''); 
    
    // Safely decompose Unicode arrays to ensure emojis do not split!
    const characters = Array.from(text);
    
    const timer = setInterval(() => {
      if (index < characters.length) {
        currentText += characters[index];
        setDisplayed(currentText);
        index++;
        if (onUpdate) onUpdate();
      } else {
        clearInterval(timer);
        isFinished.current = true;
        if (onComplete) onComplete();
      }
    }, 15);
    
    return () => clearInterval(timer);
  }, [text, onComplete, onUpdate, fastForward]);

  return <span>{displayed}</span>;
};

const Kiosk = () => {
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [fastForward, setFastForward] = useState(false);

  const [messages, setMessages] = useState([
    {
      id: 1,
      sender: 'Koda',
      text: "Hello welcome to the cafe! Looking for something?",
      typewriter: true
    }
  ]);
  const [orderStage, setOrderStage] = useState('GATHERING'); 
  const messagesEndRef = useRef(null);

  useEffect(() => {
    setIsTyping(true);
  }, []);

  useEffect(() => {
    if (!isTyping) {
       messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isTyping]);

  const handleTypingComplete = useCallback(() => {
    setIsTyping(false);
  }, []);

  const handleTypingUpdate = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'auto' });
  }, []);

  const handleSend = async (overrideText) => {
    const textToProcess = typeof overrideText === 'string' ? overrideText : inputText;
    
    if (isTyping) {
       setFastForward(true);
       return;
    }
    
    if (!textToProcess.trim()) return;

    if (textToProcess === inputText) setInputText('');

    const userMsg = { id: Date.now(), sender: 'user', text: textToProcess };
    setMessages(prev => [...prev, userMsg]);
    
    setMessages(prev => [...prev, { id: 'temp-thought', sender: 'Koda', text: "...", typewriter: false }]);

    try {
      const chatHistory = messages
          .filter(m => m.sender !== 'System' && m.id !== 'temp-thought')
          .map(m => ({
             role: m.sender === 'user' ? 'user' : 'assistant',
             content: m.text
          }));

      const activePrompt = `Current Context - Weather: ${mockContext.weather}, User Mood: ${mockContext.userMood}. User past favorite orders: ${mockContext.pastOrders.join(', ')}. User Message: "${textToProcess}"`;

      const systemPrompt = `You are Koda, an intelligent, friendly barista mascot at The Seamless Cafe acting as an interactive AI kiosk. Keep responses strictly under 3 sentences. Be cheerful and use emojis. Tailor recommendations directly to the user's context and order history. 
CRITICAL: When the customer has confirmed their customized order and is fully ready to place it (or if they agree to your upsell and you tell them you will ring them up), you MUST append the exact string '[FINALIZED]' at the very end of your response so the system can process the active transaction. Never use markdown formatting like **.`;

      const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
          method: "POST",
          headers: {
             "Authorization": "Bearer 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",
             "Content-Type": "application/json"
          },
          body: JSON.stringify({
             model: "llama-3.1-8b-instant",
             messages: [
                { role: "system", content: systemPrompt },
                ...chatHistory,
                { role: "user", content: activePrompt }
             ],
             temperature: 0.7,
             max_tokens: 150
          })
      });

      const data = await res.json();
      let aiResponse = data.choices[0].message.content.trim().replace(/\*/g, '');

      let isFinalized = false;
      if (aiResponse.includes('[FINALIZED]')) {
          isFinalized = true;
          aiResponse = aiResponse.replace(/\[FINALIZED\]/g, '').trim();
      }

      setMessages(prev => prev.filter(m => m.id !== 'temp-thought'));
      
      setFastForward(false);
      setIsTyping(true); 
      setMessages(prev => [...prev, {
          id: Date.now() + 1,
          sender: 'Koda',
          text: aiResponse,
          typewriter: true 
      }]);

      if (isFinalized) {
         setOrderStage('PROCESSING');
         const timeToWait = aiResponse.length * 15 + 500;
         setTimeout(() => {
             setMessages(prev => [...prev, {
                id: Date.now() + 2,
                sender: 'System',
                isSystem: true,
                text: "⚙️ System: Executing [CHECK_INVENTORY]... Status: ITEMS_AVAILABLE"
             }]);
             setTimeout(() => {
                setMessages(prev => [...prev, {
                   id: Date.now() + 3,
                   sender: 'System',
                   isSystem: true,
                   text: "⚙️ System: Executing [PUSH_TO_KITCHEN_QUEUE]... Status: SUCCESS"
                }]);
                setTimeout(() => {
                    setFastForward(false); 
                    setIsTyping(true); 
                    setMessages(prev => [...prev, {
                       id: Date.now() + 4,
                       sender: 'Koda',
                       text: "Alright, everything is perfectly in stock and your order has been sent to the kitchen! 🎉 Your estimated wait time is about 4 minutes. Just head to the pickup counter on the right when they call your name!",
                       typewriter: true 
                    }]);
                    setOrderStage('COMPLETED');
                }, 1500);
             }, 1500);
         }, timeToWait);
      }

    } catch (e) {
      console.error("Groq API Error:", e);
      setMessages(prev => prev.filter(m => m.id !== 'temp-thought'));
      
      setFastForward(false);
      setIsTyping(true);
      setMessages(prev => [...prev, {
          id: Date.now() + 1,
          sender: 'Koda',
          text: "Oops! My brain got disconnected from the server. Can you repeat that?",
          typewriter: true 
      }]);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSend();
  };

  const handleBubbleClick = () => {
    if (isTyping) {
       setFastForward(true);
    }
  };

  return (
    <div className="flex w-full h-[100dvh] bg-[#fcfcfc] items-center justify-center overflow-hidden relative">

      <style>{`.no-scrollbar::-webkit-scrollbar { display: none; } .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }`}</style>
      
      <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'linear-gradient(#00a8e8 1px, transparent 1px), linear-gradient(90deg, #00a8e8 1px, transparent 1px)', backgroundSize: '30px 30px' }}></div>

      {/* Removing max-w bounds and adding explicit side paddings so it perfectly scales to fill any wide monitor! */}
      <div className="relative w-full h-full flex flex-row items-end z-10 px-6 md:px-12 lg:px-20 pb-8 md:pb-12 xl:pb-16 pt-8">
        
        {/* Expand mascot scaling dramatically for giant resolutions */}
        <div className="w-[35%] md:w-[30%] lg:w-[25%] h-full flex items-end justify-center pointer-events-none z-20 pb-4">
          <img 
            src={isTyping ? "/placeholder.gif" : "/placeholder.png"} 
            alt="Mascot Avatar" 
            className="w-full max-w-[400px] xl:max-w-[600px] 2xl:max-w-[750px] object-contain drop-shadow-[0_20px_40px_rgba(0,0,0,0.15)] transition-all"
          />
        </div>

        <div className="w-[65%] md:w-[70%] lg:w-[75%] h-full flex flex-col justify-end z-30 relative min-w-0">
          
          {/* Forcing explicit full-height scaling so the dialog spans top to bottom natively! */}
          <div 
            onClick={handleBubbleClick}
            className={`relative w-full h-[92%] bg-white border-[6px] xl:border-[8px] border-[#00a8e8] rounded-[2.5rem] xl:rounded-[3.5rem] p-8 md:p-12 xl:p-16 flex flex-col shadow-[0_30px_60px_rgba(0,168,232,0.1)] ${isTyping ? 'cursor-pointer' : ''}`}
          >
             
            <div className="absolute bottom-[20%] -left-[40px] xl:-left-[50px] w-0 h-0 border-y-[30px] xl:border-y-[40px] border-y-transparent border-r-[40px] xl:border-r-[50px] border-r-[#00a8e8]" />
            <div className="absolute bottom-[20%] mt-[6px] xl:mt-[8px] -left-[30px] xl:-left-[38px] w-0 h-0 border-y-[24px] xl:border-y-[32px] border-y-transparent border-r-[34px] xl:border-r-[42px] border-r-white z-10" />

            <h2 className="text-3xl md:text-5xl xl:text-6xl font-extrabold text-[#00a8e8] tracking-wider mb-6 xl:mb-10 font-sans select-none drop-shadow-sm shrink-0">
              Mascot Name
            </h2>

            {/* Scale up history flex gaps for breathing room */}
            <div className="flex-1 overflow-y-auto flex flex-col gap-6 xl:gap-10 pr-4 pl-2 mb-6 xl:mb-10 no-scrollbar min-h-0">
              {messages.map((msg, index) => {
                 const isLatest = index >= messages.length - 2;
                 return (
                 <div key={msg.id} className={`flex flex-col ${msg.sender === 'user' ? 'items-end' : msg.isSystem ? 'items-center' : 'items-start'} ${!isLatest ? 'opacity-40 scale-[0.98]' : 'opacity-100'} transition-all duration-300 origin-left`}>
                   <span className={`
                     ${msg.sender === 'user' ? 'text-2xl xl:text-3xl font-bold text-slate-500 italic bg-slate-50 px-6 py-4 rounded-3xl border border-slate-100 shadow-sm' : ''}
                     ${msg.sender === 'Koda' ? `text-2xl xl:text-4xl font-extrabold text-slate-800 leading-snug xl:leading-snug tracking-tight drop-shadow-sm` : ''}
                     ${msg.isSystem ? 'text-lg xl:text-xl font-bold text-slate-400 font-mono bg-slate-100/50 px-5 py-3 rounded-2xl' : ''}
                   `}>
                     {msg.typewriter ? (
                       <TypewriterMessage text={msg.text} onComplete={handleTypingComplete} onUpdate={handleTypingUpdate} fastForward={fastForward} />
                     ) : (
                       <>{msg.text}</>
                     )}
                   </span>
                 </div>
              )})}
              <div ref={messagesEndRef} />
            </div>

             <div className="flex flex-col gap-4 xl:gap-6 shrink-0">
               <div className="flex gap-4 xl:gap-8">
                 <button 
                   onClick={() => handleSend("I want my usual")}
                   disabled={orderStage !== 'GATHERING'}
                   className="flex-1 py-4 xl:py-6 border-[4px] xl:border-[5px] border-[#e11d48] text-[#e11d48] hover:bg-rose-50 disabled:opacity-50 disabled:cursor-not-allowed font-extrabold text-2xl xl:text-3xl rounded-3xl xl:rounded-full transition-all cursor-pointer shadow-md active:scale-95"
                 >
                   Recommended menu
                 </button>
                 <button className="flex-1 py-4 xl:py-6 border-[4px] xl:border-[5px] border-[#e11d48] text-[#e11d48] hover:bg-rose-50 disabled:opacity-50 disabled:cursor-not-allowed font-extrabold text-2xl xl:text-3xl rounded-3xl xl:rounded-full transition-all cursor-pointer shadow-md active:scale-95">
                   Show all menu
                 </button>
               </div>

               <div className="flex flex-wrap gap-3 xl:gap-4">
                 <button 
                   onClick={() => handleSend(mockContext.weather.includes('hot') ? "It's so hot today" : "It's cold and rainy")}
                   disabled={orderStage !== 'GATHERING'}
                   className="flex items-center gap-2 xl:gap-3 px-5 xl:px-6 py-3 xl:py-4 bg-blue-50/80 hover:bg-blue-100 disabled:opacity-50 disabled:cursor-not-allowed text-blue-600 rounded-full text-lg xl:text-2xl font-bold border-[2px] border-blue-100 transition-colors cursor-pointer"
                 >
                   {mockContext.weather.includes('hot') ? <Sun className="w-5 h-5 xl:w-7 xl:h-7" /> : <CloudRain className="w-5 h-5 xl:w-7 xl:h-7" />}
                   Based on current {mockContext.weather} weather...
                 </button>
                 <button 
                   onClick={() => handleSend("I feel kinda down today")}
                   disabled={orderStage !== 'GATHERING'}
                   className="flex items-center gap-2 xl:gap-3 px-5 xl:px-6 py-3 xl:py-4 bg-rose-50/80 hover:bg-rose-100 disabled:opacity-50 disabled:cursor-not-allowed text-rose-600 rounded-full text-lg xl:text-2xl font-bold border-[2px] border-rose-100 transition-colors cursor-pointer"
                 >
                   <Frown className="w-5 h-5 xl:w-7 xl:h-7" />
                   Based on your mood...
                 </button>
                 <button 
                   onClick={() => handleSend("Can I get an Iced Latte but make it half sweet with oat milk?")}
                   disabled={orderStage !== 'GATHERING'}
                   className="flex items-center gap-2 xl:gap-3 px-5 xl:px-6 py-3 xl:py-4 bg-amber-50/80 hover:bg-amber-100 disabled:opacity-50 disabled:cursor-not-allowed text-amber-600 rounded-full text-lg xl:text-2xl font-bold border-[2px] border-amber-100 transition-colors cursor-pointer"
                 >
                   <Activity className="w-5 h-5 xl:w-7 xl:h-7" />
                   Complex Customization Test
                 </button>
               </div>
               
               <div className="relative flex items-center border-[4px] xl:border-[6px] border-[#00a8e8] rounded-full overflow-hidden bg-white mt-1 xl:mt-3 group focus-within:shadow-[0_0_0_8px_rgba(0,168,232,0.15)] transition-all shrink-0">
                  <div className="pl-6 xl:pl-8 pr-3 text-[#00a8e8]">
                     <Play className="w-8 h-8 xl:w-10 xl:h-10 fill-transparent stroke-[#00a8e8] stroke-[3px] outline-none" style={{ fill: "transparent" }} />
                  </div>
                  <input 
                    type="text" 
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyDown={handleKeyDown}
                    disabled={orderStage === 'COMPLETED'}
                    placeholder={orderStage === 'COMPLETED' ? "Order finished!" : "Text here..."}
                    className="w-full bg-transparent py-4 xl:py-6 text-2xl xl:text-3xl outline-none font-bold text-[#00a8e8] placeholder:text-[#00a8e8]/50 disabled:bg-slate-50"
                  />
                  <button 
                    onClick={() => handleSend(inputText)}
                    disabled={orderStage === 'COMPLETED' || isTyping}
                    className="absolute right-3 xl:right-4 p-3 xl:p-4 bg-white hover:bg-blue-50 border-[4px] xl:border-[5px] border-[#00a8e8] disabled:border-blue-300 text-[#00a8e8] rounded-full transition-colors cursor-pointer"
                  >
                    <Send className="w-6 h-6 xl:w-8 xl:h-8" />
                  </button>
               </div>

             </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Kiosk;
